class Solution {
public:
    vector<bool> friendRequests(int n, vector<vector<int>>& restrictions, vector<vector<int>>& requests) {
        vector<bool> result(requests.size());
        vector<vector<int>> adj(n);
        for (auto& r : restrictions) {
            adj[r[0]].push_back(r[1]);
            adj[r[1]].push_back(r[0]);
        }
        for (int i = 0; i < requests.size(); ++i) {
            int u = requests[i][0], v = requests[i][1];
            if (isFriend(adj, u, v)) {
                result[i] = true;
            } else {
                result[i] = false;
            }
        }
        return result;
    }
    bool isFriend(vector<vector<int>>& adj, int u, int v) {
        vector<bool> visited(adj.size(), false);
        return dfs(adj, u, v, visited);
    }
    bool dfs(vector<vector<int>>& adj, int u, int v, vector<bool>& visited) {
        visited[u] = true;
        if (u == v) {
            return true;
        }
        for (int neighbor : adj[u]) {
            if (!visited[neighbor] && dfs(adj, neighbor, v, visited)) {
                return true;
            }
        }
        return false;
    }
};
